import{_ as r,o as t,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"遗言","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/遗言.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/遗言.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/遗言.md"};function l(p,a,i,_,b,c){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"遗言",tabindex:"-1"},[n("遗言 "),e("a",{class:"header-anchor",href:"#遗言","aria-label":'Permalink to "遗言"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="遗言-1" tabindex="-1">遗言 <a class="header-anchor" href="#遗言-1" aria-label="Permalink to &quot;遗言&quot;">​</a></h1><p>遗言<br> D+1000<br> 特异本质<br> 遗言看上去一把是黄铜质地的古旧左轮枪，梧桐木制作的枪柄上刻着这样一段话<br> 【其知者非求人，实乃出而逐人矣】<br> 这把奇怪的左轮枪弹巢内可装五发弹药，但左轮枪本身没有击锤，枪管内也不具有膛线，再加上枪身因黄铜所制，很难承受火药的冲击力，无法当作正常的枪械使用，但具有精神力的人物握住它时，便会发现其真正的作用。</p><p>人物自由动作花费一点精神力，便可在这把枪的弹巢内，生成一颗精神力子弹，随后当持有者以意志检定进行攻击时，便可消耗一枚精神力弹药，使得这次攻击具有6点武器伤害，这个效果也可以在装备者使用精神力技能进行意志对抗时生效，因此进行的精神力攻击，射程视为决心*3米或原射程取高，武器力量需求1。</p><p>遗言<br> 整轮使用，消耗一发精神力子弹对着自己的太阳穴开枪，在无人能听到的枪响过后，这颗子弹将化为某些知识流入人物的脑中，如同粘稠的蛛网，散布在大脑皮层的沟壑表面，在遗言生效的一分钟内，人物会陷入严重的幻听和幻视，所听到声音变得杂乱而怪异，看到的文字也会在蠕动扭曲中变得于真实情况不同，这一分钟内，人物在感知洞察相关的鉴定上，全部视为自动失败；<br> 处于遗言状态下，人物会获关于人物目前处境的，来自那扭曲文字抑或是怪异声音的，只言片语的提示；<br> 提示必然是真实的，但不会具体，更不会预言未来，提示可能是一个新线索的碎片，比如一个人物名字，或者一个地方，也有可能是人物已经获得相关线索，但未曾注意或推理到的事情，比如提示人物正危险之中，要小心某人等，具体由st决定。<br> 使用这种能力并非全无代价，被未知的知识追逐等同于步入疯狂，直到理智的尽头，这也是这把枪遗言名字的由来，每一次使用遗言，人物都会永久的损失6点精神力上限或一点意志上限，持有者可自由选择支付的方式。<br> 这一能力是B级、信息来源的预言效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
